// Auto-generated by Stackpanel — do not edit manually.
// Node/Bun runtime environment loader — decrypts generated per-app env payloads.

import { exec, execFile } from "node:child_process";
import { readFile, rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { promisify } from "node:util";
import { decryptSops } from "sops-age";
import { AVAILABLE_APP_ENVS } from "../embedded-data";
import type { LoadEnvOptions } from "./loader";
import { normalizeEnvPayload, normalizeRuntimeEnv } from "./loader";
import { loadGeneratedPayload } from "../generated-payloads/registry";

const execAsync = promisify(exec);
const execFileAsync = promisify(execFile);
const AGE_SECRET_KEY_PREFIX = "AGE-SECRET-KEY-";
const payloadCache = new Map<string, Record<string, string>>();

type SopsFileType = "json";

export async function loadEnv(
  app: string,
  env: string,
  options: LoadEnvOptions = {},
): Promise<Record<string, string>> {
  const normalizedEnv = normalizeRuntimeEnv(env);
  const cacheKey = `${app}/${normalizedEnv}`;
  const cached = payloadCache.get(cacheKey);
  if (cached) {
    injectIntoProcessEnv(cached, options.inject);
    return cached;
  }

  const encryptedPayload = await loadGeneratedPayload(app, normalizedEnv);
  if (!encryptedPayload) {
    const knownEnvs = AVAILABLE_APP_ENVS[app] || [];
    const hint = knownEnvs.length > 0 ? ` Available environments: ${knownEnvs.join(", ")}.` : "";
    throw new Error(`Environment data not found for ${app}/${normalizedEnv}.${hint}`);
  }

  const payload = normalizeEnvPayload(
    await decryptStructuredContent(encryptedPayload, "json", options.secretKey),
  );
  payloadCache.set(cacheKey, payload);
  injectIntoProcessEnv(payload, options.inject);
  return payload;
}

export async function loadSharedVars(
  options: Omit<LoadEnvOptions, "skipDecrypt"> = {},
): Promise<Record<string, string>> {
  const envObject = getProcessEnv();
  const appName = envObject.APP_NAME || "web";
  const envName = normalizeRuntimeEnv(envObject.APP_ENV || envObject.NODE_ENV || "prod");
  return loadEnv(appName, envName, options);
}

export async function loadAppEnv(
  app: string,
  env: string,
  options: LoadEnvOptions = {},
): Promise<Record<string, string>> {
  return loadEnv(app, env, options);
}

async function decryptStructuredContent(
  content: string,
  fileType: SopsFileType,
  secretKey?: string,
): Promise<Record<string, unknown>> {
  const secretKeys = await resolveRuntimeSecretKeys(secretKey);
  if (secretKeys.length > 0) {
    return decryptWithJsKeysFromContent(content, fileType, secretKeys);
  }

  if (process.env.SOPS_KEYSERVICE) {
    return decryptWithSopsBinary(content, fileType);
  }

  throw new Error(missingKeyMaterialMessage());
}

async function decryptWithJsKeysFromContent(
  content: string,
  fileType: SopsFileType,
  secretKeys: string[],
): Promise<Record<string, unknown>> {
  const errors: string[] = [];

  for (const key of secretKeys) {
    try {
      const result = await decryptSops(content, { fileType, secretKey: key });
      return (result as Record<string, unknown>) || {};
    } catch (error: any) {
      errors.push(error?.message || String(error));
    }
  }

  throw new Error(`Failed to decrypt generated payload: ${errors.join("; ")}`);
}

async function decryptWithSopsBinary(
  content: string,
  fileType: SopsFileType,
): Promise<Record<string, unknown>> {
  const tempPath = join(tmpdir(), `stackpanel-env-${Date.now()}.sops.json`);
  try {
    await writeFile(tempPath, content, "utf8");
    const { stdout } = await execFileAsync(
      "sops",
      ["--decrypt", "--input-type", fileType, "--output-type", "json", tempPath],
      {
        env: process.env,
        maxBuffer: 10 * 1024 * 1024,
      },
    );
    return (JSON.parse(stdout) as Record<string, unknown>) || {};
  } catch (error: any) {
    if (error?.code === "ENOENT") {
      throw new Error(
        "SOPS keyservice is configured via SOPS_KEYSERVICE, but the `sops` binary is not installed.",
      );
    }
    const stderr = error?.stderr ? String(error.stderr).trim() : "";
    const detail = stderr || error?.message || String(error);
    throw new Error(`Failed to decrypt generated payload with the sops binary: ${detail}`);
  } finally {
    try {
      await rm(tempPath, { force: true });
    } catch {}
  }
}

async function resolveRuntimeSecretKeys(explicitSecretKey?: string): Promise<string[]> {
  if (explicitSecretKey) {
    return parseAgeSecretKeys(explicitSecretKey);
  }

  const envKeys = parseAgeSecretKeys(process.env.SOPS_AGE_KEY);
  if (envKeys.length > 0) {
    return envKeys;
  }

  const repoLocalKey = await readRepoLocalAgeKey();
  if (repoLocalKey) {
    const repoKeys = parseAgeSecretKeys(repoLocalKey);
    if (repoKeys.length > 0) {
      return repoKeys;
    }
  }

  const command = process.env.SOPS_AGE_KEY_CMD;
  if (!command) {
    return [];
  }

  const { stdout } = await execAsync(command, { maxBuffer: 1024 * 1024 });
  return parseAgeSecretKeys(stdout);
}

async function readRepoLocalAgeKey(): Promise<string | null> {
  const explicitKeysDir = process.env.STACKPANEL_KEYS_DIR;
  const candidate = explicitKeysDir
    ? join(explicitKeysDir, "local.txt")
    : join(process.cwd(), ".stack", "keys", "local.txt");

  try {
    return await readFile(candidate, "utf8");
  } catch {
    return null;
  }
}

function parseAgeSecretKeys(input?: string): string[] {
  if (!input) {
    return [];
  }

  const keys = input
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line.startsWith(AGE_SECRET_KEY_PREFIX));

  return [...new Set(keys)];
}

function injectIntoProcessEnv(payload: Record<string, string>, inject = true) {
  if (inject === false) {
    return;
  }
  Object.assign(process.env, payload);
}

function getProcessEnv(): Record<string, string | undefined> {
  return process.env as Record<string, string | undefined>;
}

function missingKeyMaterialMessage(): string {
  return "No SOPS decryption method is configured. Set SOPS_AGE_KEY or SOPS_AGE_KEY_CMD, or set SOPS_KEYSERVICE and install the `sops` binary.";
}
